dark.customCSS:
/* --- TOXIC NEBULA: ATMOSPHERIC SMOG UI --- */

@keyframes liquid-pulse {
  0% { box-shadow: 0 0 10px rgba(0, 255, 65, 0.2); }
  50% { box-shadow: 0 0 25px rgba(0, 255, 65, 0.4); }
  100% { box-shadow: 0 0 10px rgba(0, 255, 65, 0.2); }
}

/* The Haze Container */
.prose, .bg-gray-850, #sidebar, input, textarea {
	background: rgba(17, 0, 28, 0.5) !important;
	backdrop-filter: blur(25px) saturate(1.6) !important;
	-webkit-backdrop-filter: blur(25px) saturate(1.6) !important;
	border: 1px solid transparent !important;
	border-image: linear-gradient(to bottom right, #b133ff, #00ff41) 1 !important;
	border-radius: 0px !important; /* Brutalist corners */
}

/* Acid Typography */
.prose h1, .prose h2, .prose h3 {
	color: #00ff41 !important;
	text-transform: uppercase;
	letter-spacing: 3px;
	text-shadow: 
		0 0 10px rgba(0, 255, 65, 0.5),
		0 0 20px rgba(177, 51, 255, 0.3) !important;
}

/* Radioactive Buttons */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #00ff41 !important;
	color: #04000a !important;
	border: none !important;
	border-radius: 4px !important;
	font-weight: 900 !important;
	letter-spacing: 1px;
	animation: liquid-pulse 3s infinite ease-in-out;
	transition: all 0.2s ease;
}

button.bg-blue-500:hover {
	background: #fff !important;
	transform: scale(1.05);
	box-shadow: 0 0 40px #00ff41 !important;
}

/* Sludge Scrollbar */
::-webkit-scrollbar {
	width: 8px;
}
::-webkit-scrollbar-thumb {
	background: #00ff41 !important;
	border-radius: 0px;
	box-shadow: 0 0 10px #00ff41;
}
::-webkit-scrollbar-track {
	background: #04000a !important;
}

/* Interactive Input Focus */
input:focus, textarea:focus {
	background: rgba(30, 0, 50, 0.8) !important;
	outline: 2px solid #00ff41 !important;
	outline-offset: 4px;
}

dark.canvasScript:
/**
 * Title: Corrosive Effluence (Smog)
 * Description: Heavy toxic gas clouds that billow and part when the mouse moves through them.
 */

const CONFIG = {
    cloudCount: 10,
    minSize: 400,
    maxSize: 800,
    purpleAlpha: 0.08,
    greenAlpha: 0.12,
    driftSpeed: 0.6,
    mouseDissipation: 400
};

let canvas, ctx, w, h;
let clouds = [];
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    clouds = [];
    for (let i = 0; i < CONFIG.cloudCount; i++) {
        clouds.push({
            x: Math.random() * w, y: Math.random() * h,
            r: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            vx: (Math.random() - 0.5) * CONFIG.driftSpeed,
            vy: (Math.random() - 0.5) * CONFIG.driftSpeed,
            phase: Math.random() * Math.PI * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    ctx.globalCompositeOperation = 'screen';

    for (let c of clouds) {
        c.x += c.vx + Math.sin(c.phase) * 0.2;
        c.y += c.vy + Math.cos(c.phase) * 0.2;
        c.phase += 0.005;

        // Dissipation near mouse
        let dx = mouse.x - c.x; let dy = mouse.y - c.y; let dist = Math.hypot(dx, dy);
        let opacityMult = 1;
        if (dist < CONFIG.mouseDissipation) {
            opacityMult = dist / CONFIG.mouseDissipation;
            c.x -= (dx / dist) * 2; // Subtle push away
        }

        // Wrap edges
        if (c.x < -c.r) c.x = w + c.r; if (c.x > w + c.r) c.x = -c.r;
        if (c.y < -c.r) c.y = h + c.r; if (c.y > h + c.r) c.y = -c.r;

        let grad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, c.r);
        grad.addColorStop(0, `rgba(0, 255, 65, ${CONFIG.greenAlpha * opacityMult})`);
        grad.addColorStop(0.4, `rgba(177, 51, 255, ${CONFIG.purpleAlpha * opacityMult})`);
        grad.addColorStop(1, 'rgba(0, 0, 0, 0)');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(c.x, c.y, c.r, 0, Math.PI * 2);
        ctx.fill();
    }

    requestAnimationFrame(render);
}

